import os
import shutil
import stat

# The rogue .git directory that is tracking the whole user profile
rogue_git_dir = r"C:\Users\hiroy\.git"

def remove_readonly(func, path, excinfo):
    os.chmod(path, stat.S_IWRITE)
    func(path)

if os.path.exists(rogue_git_dir):
    try:
        print(f"Removing rogue .git directory at {rogue_git_dir}...")
        shutil.rmtree(rogue_git_dir, onerror=remove_readonly)
        print("Successfully removed the rogue .git directory. Your system is no longer being tracked by Git.")
    except Exception as e:
        print(f"Error removing .git directory: {e}")
else:
    print(f"Rogue .git directory not found at {rogue_git_dir}. It might have been moved or deleted.")
